using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
        StringAssert.StartsWith(result, "(123)");
        StringAssert.EndsWith(result, "7890");
        StringAssert.Contains(result, "456");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_Null_Throws() =>
        _formatter.FormatPhoneNumber(null!);

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_Throws() =>
        _formatter.FormatPhoneNumber("123");

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_NameOnly_UsesDefaultTitle()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
        StringAssert.StartsWith(result, "Dear Mr.");
        StringAssert.EndsWith(result, "Smith,");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        StringAssert.EndsWith(result, "Jones,");
    }

    [TestMethod]
    public void BuildGreeting_Result_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson", "Ms.");

        StringAssert.Contains(result, "Anderson");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws() =>
        _formatter.BuildGreeting("   ");

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_EmptyName_Throws() =>
        _formatter.BuildGreeting("");

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StripsNonAlphanumeric()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        StringAssert.StartsWith(result, "c-");
        StringAssert.EndsWith(result, "great");
        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^[a-z0-9\-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_AreStripped()
    {
        var result = _formatter.GenerateSlug("  Padded Title  ");

        Assert.AreEqual("padded-title", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_Whitespace_Throws() =>
        _formatter.GenerateSlug("   ");

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
        StringAssert.EndsWith(result, "9.99");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(1234.50m, "€");

        StringAssert.StartsWith(result, "€");
        StringAssert.EndsWith(result, "1234.50");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_HasTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(42m);

        Assert.AreEqual("$42.00", result);
        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.75m);

        StringAssert.Contains(result, "-");
        StringAssert.EndsWith(result, "5.75");
    }
}

